{
    // 设置 PATH
    "latex-workshop.latex.env": {
        "PATH": "/Library/TeX/texbin:/usr/local/bin:/opt/homebrew/bin:/usr/bin:/bin"
    },
    "latex-workshop.latex.build.forceRecompile": true,
    "latex-workshop.latex.autoBuild.run": "never",

    // 定义编译工具
    "latex-workshop.latex.tools": [
        {
            "name": "xelatex",
            "command": "/Library/TeX/texbin/xelatex",
            "args": [
                "-synctex=1",
                "-interaction=nonstopmode",
                "-file-line-error",
                "-halt-on-error",
                "%DOC%"
            ]
        },
        {
            "name": "latexmk",
            "command": "/Library/TeX/texbin/latexmk",
            "args": [
                "-e",
                "$xelatex = '/Library/TeX/texbin/xelatex'",
                "-synctex=1",
                "-interaction=nonstopmode",
                "-file-line-error",
                "-pdf",
                "-xelatex",
                "-halt-on-error",
                "-f",
                "%DOC%"
            ]
        }
    ],

    // 定义编译 recipe
    "latex-workshop.latex.recipes": [
        {
            "name": "xelatex 编译",
            "tools": ["xelatex"]
        },
        {
            "name": "latexmk 编译",
            "tools": ["latexmk"]
        }
    ],
    "latex-workshop.latex.recipe.default": "xelatex 编译",

    // 使用外部 PDF 查看器
    "latex-workshop.view.pdf.viewer": "external",

    // 打开 PDF 时调用 Skim
    "latex-workshop.view.pdf.external.viewer.command": "/Applications/Skim.app/Contents/SharedSupport/displayline",
    "latex-workshop.view.pdf.external.viewer.args": [
        "0",
        "%PDF%"
    ],

    // 正向同步（VSCode → Skim）
    "latex-workshop.view.pdf.external.synctex.command": "/Applications/Skim.app/Contents/SharedSupport/displayline",
    "latex-workshop.view.pdf.external.synctex.args": [
        "-revert",
        "-readingbar",
        "-background",
        "%LINE%",
        "%PDF%",
        "%TEX%"
    ],

    // 启用 SyncTeX 服务器（反向同步需要）
    "latex-workshop.synctex.enabled": true,
    "latex-workshop.synctex.synctexArgs": [
        "--interact=nonstopmode"
    ],
    "latex-workshop.view.pdf.external.synctex.reverseSync": true
}

